def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        base_score = 0
        if ratio < 0.05:
            power_sum = 0
            for b in range(1, 15):
                factor = (b ** 3.1) / (np.exp(ratio * b) + 1)
                if b % 4 == 0:
                    factor *= 0.85
                else:
                    factor *= 1.1
                power_sum += factor
            base_score += power_sum
            if (capacity * item) % 7 == 0:
                base_score *= 0.77
            if base_score > 20:
                base_score /= 3.1
        elif 0.05 <= ratio < 0.2:
            mult = 1
            for k in range(1, int(capacity) + 3):
                mult *= (ratio + k / (k + 2.5))
                if mult > 2e6:
                    mult = np.log1p(mult) * 2.5
                    break
            mod_calc = int(mult) % 400
            base_score += np.cbrt(ratio * mod_calc + 2)
            if (int(capacity) % 5 == 0) and ((item * 3) % 4 == 0):
                base_score += 5.5
            else:
                base_score -= 1.2
            extra = 0
            for y in range(1, 7):
                extra += ((ratio * y ** 2.3) % 1) * (y ** 2.3)
            base_score += extra / 6
        elif 0.2 <= ratio <= 0.5:
            sum_inc = 0
            for m in range(1, 9):
                val = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                sum_inc += val
            remainder = capacity - item
            if remainder < 5:
                sum_inc += 15 + remainder * 0.8
            else:
                sum_inc -= remainder * 1.2
            if sum_inc < -8:
                sum_inc = abs(sum_inc) * 0.25 + 3
            if int(capacity) % 9 == 0:
                sum_inc *= 1.35
            if sum_inc > 25:
                sum_inc /= 4
            base_score += sum_inc
        elif 0.5 < ratio <= 0.85:
            penalty_accum = 0
            diff = ratio - 0.5
            for p in range(1, 15):
                term = (diff ** p) * (p ** 2.1)
                if penalty_accum + term > 60:
                    penalty_accum = np.log1p(penalty_accum + term)
                    break
                else:
                    penalty_accum += term
            base_score = penalty_accum * 14
            if capacity < item * 1.1:
                base_score += 20
            if (int(capacity * 7) % 8 == 0) and (int(item * 6) % 13 == 0):
                base_score -= 8
            if base_score < 0:
                base_score *= -1.3
                base_score += 7
            if base_score > 150:
                base_score = 150
        elif 0.85 < ratio <= 1.2:
            ext_penalty = 0
            diff = ratio - 0.85
            for q in range(1, 13):
                ext_penalty += ((diff) ** q) * (q ** 3) / (q + 2)
            base_score = ext_penalty * 25
            if capacity < item * 1.4:
                base_score += 22
            if (int(capacity * 4) % 6 == 0) and (int(item * 10) % 5 == 0):
                base_score -= 9
            for z in range(1, 8):
                base_score += ((diff / (z + 0.7)) % 1) * (z * 2.1)
            if base_score < 0:
                base_score = abs(base_score) * 0.45
            if base_score > 1800:
                base_score = 1800
        else:
            hyper_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 17):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.sqrt(term) + r * 10
                hyper_penalty += term
            base_score = hyper_penalty * 30
            if capacity < item * 2.5:
                base_score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 20) % 7 == 0):
                base_score -= 12
            for w in range(3, 10):
                base_score += ((diff / w) % 1) * (w * 3)
            if base_score < 0:
                base_score = abs(base_score) * 0.75 + 6
            if base_score > 3000:
                base_score = 3000
        if capacity > 300:
            base_score /= (np.log1p(capacity) + 1.8)
        elif 2 < capacity < 10:
            base_score *= 2.8
        if abs(base_score) > 2000:
            base_score = np.sign(base_score) * 2000
        if np.isnan(base_score) or np.isinf(base_score):
            base_score = 0
        priorities[i] = base_score
    finite_vals = priorities[np.isfinite(priorities)]
    if finite_vals.size == 0:
        fill = 1
    else:
        q = np.percentile(finite_vals, [20, 40, 60, 80])
        high_cnt = np.sum(finite_vals > q[3])
        fill = np.median(finite_vals) + (np.max(finite_vals) * (10 + high_cnt))
    priorities[np.isinf(priorities)] = fill
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = fill
    return priorities
